// const — binding cannot be reassigned
const name = 'SkillSprint';
// name = 'Other'; // ❌ TypeError

// let — reassignable, block-scoped
let score = 0;
score = 42; // ✅

// var — function-scoped (avoid)
var legacy = true;

// const with objects — object itself is mutable
const user = { age: 21 };
user.age = 22; // ✅ the object's properties can change
